-- Additive trusted-upload completion. Service workers record the validated human actor; clients never invoke these writers.
alter table public.policy_documents add column upload_authorization_id uuid references public.policy_upload_authorizations(id) on delete restrict;
alter table public.policy_documents add constraint policy_documents_upload_authorization_unique unique(upload_authorization_id);
alter table public.policy_upload_authorizations add column checksum_verification_status text not null default 'pending' check(checksum_verification_status in ('pending','verified','failed'));

create or replace function public.append_policy_audit_event_for_actor(p_t uuid,p_o uuid,p_f uuid,p_actor uuid,p_permission text,p_action text,p_entity_type text,p_entity_id uuid,p_metadata jsonb default '{}'::jsonb) returns uuid language plpgsql security definer set search_path=public as $$ declare event_id uuid; begin if auth.role()<>'service_role' or p_metadata ?| array['password','token','secret','access_token'] or not public.policy_member_in_scope(p_actor,p_t,p_o,p_f) or not public.policy_actor_has_permission(p_actor,p_permission,p_t,p_o,p_f) then raise exception 'Trusted policy audit actor is not authorized'; end if; insert into public.audit_events(tenant_id,organization_id,facility_id,actor_id,action,entity_type,entity_id,metadata) values(p_t,p_o,p_f,p_actor,p_action,p_entity_type,p_entity_id,p_metadata) returning id into event_id; return event_id; end $$;
create or replace function public.record_policy_event_for_actor(p_policy uuid,p_version uuid,p_t uuid,p_o uuid,p_f uuid,p_actor uuid,p_permission text,p_action text,p_metadata jsonb default '{}'::jsonb) returns void language plpgsql security definer set search_path=public as $$ begin if auth.role()<>'service_role' or not public.policy_member_in_scope(p_actor,p_t,p_o,p_f) or not public.policy_actor_has_permission(p_actor,p_permission,p_t,p_o,p_f) then raise exception 'Trusted policy event actor is not authorized'; end if; insert into public.policy_events(policy_definition_id,policy_version_id,tenant_id,organization_id,facility_id,actor_id,action,metadata) values(p_policy,p_version,p_t,p_o,p_f,p_actor,p_action,p_metadata); perform public.append_policy_audit_event_for_actor(p_t,p_o,p_f,p_actor,p_permission,p_action,'policy_definition',p_policy,p_metadata); end $$;

-- INSERT is authorization-bound; a draft path alone is not sufficient.
create or replace function public.policy_storage_object_allowed(p_name text,p_write boolean) returns boolean language plpgsql security definer set search_path=public,storage as $$ declare v uuid; begin if auth.uid() is null or p_name !~ '^tenant/[0-9a-f-]{36}/organization/[0-9a-f-]{36}/facility/([0-9a-f-]{36}|global)/policies/[0-9a-f-]{36}/versions/[0-9a-f-]{36}/[0-9a-f-]{36}-[A-Za-z0-9._-]+$' then return false; end if; v:=split_part(p_name,'/',10)::uuid; if p_write then return exists(select 1 from public.policy_upload_authorizations a join public.policy_versions x on x.id=a.policy_version_id where a.storage_key=p_name and a.uploader_id=auth.uid() and a.expires_at>now() and a.finalized_at is null and a.checksum_verification_status='pending' and x.id=v and x.tenant_id=split_part(p_name,'/',2)::uuid and x.organization_id=split_part(p_name,'/',4)::uuid and coalesce(x.facility_id::text,'global')=split_part(p_name,'/',6) and x.status='draft' and public.can_policy('policies.edit',x.tenant_id,x.organization_id,x.facility_id)); end if; return exists(select 1 from public.policy_documents d left join public.policy_upload_authorizations a on a.id=d.upload_authorization_id where d.storage_bucket='policy-documents' and d.storage_key=p_name and (a.id is null or (a.malware_scan_status='accepted' and a.checksum_verification_status='verified')) and public.can_view_policy_document(d.policy_version_id)); end $$;
drop policy if exists policy_documents_storage_insert on storage.objects;
create policy policy_documents_storage_insert on storage.objects for insert to authenticated with check(bucket_id='policy-documents' and public.policy_storage_object_allowed(name,true));

create or replace function public.finalize_policy_document_verified(p_authorization uuid,p_mime text,p_language public.content_language,p_label text,p_preview boolean,p_source text,p_extracted text default null) returns uuid language plpgsql security definer set search_path=public,storage as $$ declare a public.policy_upload_authorizations%rowtype; v public.policy_versions%rowtype; object_size bigint; extension text; id uuid; allow_pending boolean; begin if auth.role()<>'service_role' then raise exception 'Trusted policy upload finalization requires service role'; end if; select * into a from public.policy_upload_authorizations where id=p_authorization for update; if not found or a.finalized_at is not null or a.expires_at<=now() or a.checksum_verification_status<>'verified' then raise exception 'Policy upload finalization denied'; end if; allow_pending:=current_setting('app.policy_non_production',true)='on'; if a.malware_scan_status<>'accepted' and not (allow_pending and a.malware_scan_status='pending') then raise exception 'Policy malware scan is not accepted'; end if; select * into v from public.policy_versions where id=a.policy_version_id for update; if not found or v.status<>'draft' or not public.policy_member_in_scope(a.uploader_id,v.tenant_id,v.organization_id,v.facility_id) or not public.policy_actor_has_permission(a.uploader_id,'policies.edit',v.tenant_id,v.organization_id,v.facility_id) then raise exception 'Policy upload finalization denied'; end if; select nullif(metadata->>'size','')::bigint into object_size from storage.objects where bucket_id='policy-documents' and name=a.storage_key; if object_size is null or object_size<>a.expected_size then raise exception 'Policy upload object verification failed'; end if; extension:=lower(regexp_replace(a.storage_key,'^.*\.','','')); if extension not in ('pdf','docx','doc','xlsx','xls','pptx','jpg','jpeg','png','webp') or (extension='pdf' and p_mime<>'application/pdf') or (extension='docx' and p_mime<>'application/vnd.openxmlformats-officedocument.wordprocessingml.document') or (extension='doc' and p_mime<>'application/msword') or (extension='xlsx' and p_mime<>'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet') or (extension='xls' and p_mime<>'application/vnd.ms-excel') or (extension='pptx' and p_mime<>'application/vnd.openxmlformats-officedocument.presentationml.presentation') or (extension in ('jpg','jpeg') and p_mime<>'image/jpeg') or (extension='png' and p_mime<>'image/png') or (extension='webp' and p_mime<>'image/webp') or coalesce(trim(p_label),'')='' or p_source not in ('upload','word_import') then raise exception 'Policy upload MIME or metadata is invalid'; end if; insert into public.policy_documents(policy_version_id,tenant_id,organization_id,facility_id,storage_bucket,storage_key,checksum,mime_type,byte_size,document_language,version_label,preview_available,extracted_text,source_type,uploaded_by,upload_authorization_id) values(v.id,v.tenant_id,v.organization_id,v.facility_id,'policy-documents',a.storage_key,a.expected_checksum,p_mime,a.expected_size,p_language,trim(p_label),p_preview,p_extracted,p_source,a.uploader_id,a.id) returning id into id; update public.policy_upload_authorizations set finalized_at=now() where id=a.id; perform public.record_policy_event_for_actor(v.policy_definition_id,v.id,v.tenant_id,v.organization_id,v.facility_id,a.uploader_id,'policies.edit','policy.document_uploaded',jsonb_build_object('document_id',id,'authorization_id',a.id)); return id; end $$;
create or replace function public.delete_draft_policy_document(p_document uuid,p_actor uuid) returns void language plpgsql security definer set search_path=public as $$ declare d public.policy_documents%rowtype; v public.policy_versions%rowtype; begin if auth.role()<>'service_role' then raise exception 'Trusted policy document deletion requires service role'; end if; select * into d from public.policy_documents where id=p_document for update; if not found then raise exception 'Policy document deletion denied'; end if; select * into v from public.policy_versions where id=d.policy_version_id for update; if not found or v.status<>'draft' or not public.policy_member_in_scope(p_actor,v.tenant_id,v.organization_id,v.facility_id) or not public.policy_actor_has_permission(p_actor,'policies.edit',v.tenant_id,v.organization_id,v.facility_id) then raise exception 'Policy document deletion denied'; end if; delete from public.policy_documents where id=d.id; perform public.record_policy_event_for_actor(v.policy_definition_id,v.id,v.tenant_id,v.organization_id,v.facility_id,p_actor,'policies.edit','policy.document_deleted',jsonb_build_object('document_id',d.id)); end $$;

revoke all on function public.append_policy_audit_event_for_actor(uuid,uuid,uuid,uuid,text,text,text,uuid,jsonb),public.record_policy_event_for_actor(uuid,uuid,uuid,uuid,uuid,uuid,text,text,jsonb),public.policy_storage_object_allowed(text,boolean) from public,anon,authenticated;
revoke all on function public.finalize_policy_document_verified(uuid,text,public.content_language,text,boolean,text,text),public.delete_draft_policy_document(uuid,uuid) from public,anon,authenticated;
grant execute on function public.finalize_policy_document_verified(uuid,text,public.content_language,text,boolean,text,text),public.delete_draft_policy_document(uuid,uuid) to service_role;
